    @Volatile
    var minimumLevel: Level = Level.VERBOSE

    @Volatile
    var includeSensitiveData: Boolean = false

    private val redactionKeys = setOf(
        "authorization",
        "proxy-authorization",
        "cookie",
        "set-cookie",
        "password",
        "pass",
        "token",
        "access_token",
        "refresh_token",
