    fun init(context: Context) {
        val appInfo = context.applicationInfo
        enabled = (appInfo.flags and android.content.pm.ApplicationInfo.FLAG_DEBUGGABLE) != 0
        minimumLevel = if (enabled) Level.VERBOSE else Level.INFO
    }

    fun v(tag: String = DEFAULT_TAG, message: String) = log(Level.VERBOSE, tag, message)
    fun d(tag: String = DEFAULT_TAG, message: String) = log(Level.DEBUG, tag, message)
    fun i(tag: String = DEFAULT_TAG, message: String) = log(Level.INFO, tag, message)
    fun w(tag: String = DEFAULT_TAG, message: String) = log(Level.WARN, tag, message)
    fun e(tag: String = DEFAULT_TAG, message: String, tr: Throwable? = null) = log(Level.ERROR, tag, message, tr)

    fun log(level: Level, tag: String = DEFAULT_TAG, message: String, tr: Throwable? = null) {
