    private fun redactHeaders(headers: Map<String, String>): Map<String, String> {
        if (includeSensitiveData) return headers
        return headers.mapValues { (key, value) ->
            if (redactionKeys.any { it.equals(key, ignoreCase = true) }) "***REDACTED***" else redactValue(value)
        }
    }

    private fun redactMap(map: Map<String, String>): Map<String, String> {
        return map.mapValues { (key, value) ->
            if (redactionKeys.any { it.equals(key, ignoreCase = true) }) "***REDACTED***" else redactValue(value)
        }
    }

    private fun redactBody(body: String): String {
        if (body.isBlank()) return body
        var redacted = body
        redacted = Regex("(?i)(\"?(?:password|token|access_token|refresh_token|api-key|x-api-key)\"?\\s*[:=]\\s*\")([^\"]+)(\")")
            .replace(redacted) { matchResult -> "${matchResult.groupValues[1]}***REDACTED***${matchResult.groupValues[3]}" }
        redacted = Regex("(?i)(password|token|access_token|refresh_token|api-key|x-api-key)(\\s*[:=]\\s*)([^,&\\s]+)")
            .replace(redacted) { matchResult -> "${matchResult.groupValues[1]}${matchResult.groupValues[2]}***REDACTED***" }
        return redacted
    }

    private fun redactValue(value: Any?): Any? {
        return when (value) {
            null -> null
            is String -> if (looksSensitive(value)) "***REDACTED***" else value
            else -> value
        }
    }

    private fun looksSensitive(value: String): Boolean {
        val lower = value.lowercase()
        return redactionKeys.any { lower.contains(it) } || value.length > 64 && value.matches(Regex("[A-Za-z0-9+/=_-]+"))
    }

    private fun formatMap(map: Map<*, *>): String {
        if (map.isEmpty()) return "{}"
        return map.entries.joinToString(prefix = "{", postfix = "}") { (k, v) ->
            "${k.toString()}=${v.toString()}"
        }
    }

    private fun stackTraceToString(tr: Throwable): String {
        val sw = StringWriter()
        val pw = PrintWriter(sw)
        tr.printStackTrace(pw)
        pw.flush()
        return sw.toString()
    }

    private fun requestFingerprint(
        method: String,
        url: String,
        headers: Map<String, String>,
        body: String?,
        queryParams: Map<String, String>
    ): String {
        return buildString {
            append(method).append('|').append(url).append('|')
            append(headers.hashCode()).append('|')
            append(body?.hashCode() ?: 0).append('|')
            append(queryParams.hashCode())
        }
    }

    private fun shouldThrottle(fingerprint: String): Boolean {
        val now = System.currentTimeMillis()
        val last = recentEvents.put(fingerprint, now)
        return last != null && now - last < 250
    }
