class LoggingTimberTree : timber.log.Timber.Tree() {
    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
        val finalTag = tag ?: "Timber"
        when (priority) {
            Log.VERBOSE -> Log.v(finalTag, message, t)
            Log.DEBUG -> Log.d(finalTag, message, t)
            Log.INFO -> Log.i(finalTag, message, t)
            Log.WARN -> Log.w(finalTag, message, t)
            Log.ERROR -> Log.e(finalTag, message, t)
            Log.ASSERT -> Log.wtf(finalTag, message, t)
        }
        if (t != null && priority < Log.ERROR) {
            Log.e(finalTag, AppLogger.run { t.stackTraceToString(t) })
        }
    }
}

class LoggingExceptionHandler(
    private val previous: Thread.UncaughtExceptionHandler? = Thread.getDefaultUncaughtExceptionHandler()
) : Thread.UncaughtExceptionHandler {
    override fun uncaughtException(thread: Thread, throwable: Throwable) {
        AppLogger.logException(throwable, "Uncaught exception on thread=${thread.name}", tag = "Crash")
        previous?.uncaughtException(thread, throwable)
    }
}

class ProdLoggingInitializer(private val context: Context) {
    fun initialize() {
        AppLogger.init(context)
        if (AppLogger.enabled) {
            timber.log.Timber.plant(LoggingTimberTree())
            Thread.setDefaultUncaughtExceptionHandler(LoggingExceptionHandler())
            AppLogger.i("Init", "Comprehensive logging initialized")
        } else {
            timber.log.Timber.plant(timber.log.Timber.DebugTree())
            AppLogger.i("Init", "Production logging initialized in restricted mode")
        }
    }
}

